    59→    ) => {
    60→        const calculateArcPath = (projection, start, end) => {
    61→            const start2D = projection([start.lng, start.lat]);
    62→            const end2D = projection([end.lng, end.lat]);
    63→            if (!start2D || !end2D) return '';
    64→            const midX = (start2D[0] + end2D[0]) / 2;
    65→            const midY = (start2D[1] + end2D[1]) / 2 - curveHeight * 100;
    66→            return `M ${start2D[0]},${start2D[1]} Q ${midX},${midY} ${end2D[0]},${end2D[1]}`;
    67→        };
    68→
    69→        const getLabelXOffset = (position, iconSize, labelSize) => {
    70→            switch (position) {
    71→                case 'right':
    72→                    return iconSize
    73→                case 'left':
    74→                    return -(iconSize * 1.2); // Place label to the left of the icon
    75→                default:
    76→                    return 0; // Center for top or bottom
    77→            }
    78→        };
    79→
    80→        const getLabelYOffset = (position, iconSize, labelSize) => {
    81→            switch (position) {
    82→                case 'top':
    83→                    return -(iconSize * 1.2 + labelSize * 0.1); // Place label above the icon
    84→                case 'bottom':
    85→                    return iconSize * 1.2 + labelSize * 0.6; // Place label below the icon
    86→                default:
    87→                    return labelSize * 0.3; // Slight vertical adjustment for left/right
    88→            }
    89→        };
    90→
    91→
    92→        return (
    93→            <div ref={ref} style={{ width: '100%', height: '100%' }}>
    94→                <ComposableMap projection="geoMercator" style={{ width: '100%', height: '100%' }}>
    95→                    <ZoomableGroup>
    96→                        <Geographies geography="https://cdn.jsdelivr.net/npm/world-atlas@2/countries-110m.json">
    97→                            {({ geographies, projection }) => (
    98→                                <>
    99→                                    {geographies.map((geo) => (
   100→                                        <Geography key={geo.rsmKey} geography={geo} fill="#DDD" stroke="#FFF" />
   101→                                    ))}
   102→                                    <path
   103→                                        d={calculateArcPath(projection, startPoint, endPoint)}
   104→                                        fill="none"
   105→                                        stroke={arcColor}
   106→                                        strokeWidth={arcWidth}
   107→                                        strokeDasharray={arcDashArray}
   108→                                    />
   109→                                    {/* Travel Icon */}
   110→                                    {(() => {
   111→                                        const start2D = projection([startPoint.lng, startPoint.lat]);
   112→                                        const end2D = projection([endPoint.lng, endPoint.lat]);
   113→                                        if (!start2D || !end2D || !travelModeIcon) return null;
   114→
   115→                                        const iconX = (start2D[0] + end2D[0]) / 2;
   116→                                        const iconY = (start2D[1] + end2D[1]) / 2 - curveHeight * 50;
   117→
   118→                                        return (
   119→                                            <g transform={`translate(${iconX}, ${iconY})`}>
   120→                                                <circle
   121→                                                    r={travelIconSize * 0.8}
   122→                                                    fill={travelIconColor}
   123→
   124→                                                />
   125→                                                {availableIcons[travelModeIcon] &&
   126→                                                    React.cloneElement(availableIcons[travelModeIcon], {
   127→                                                        size: travelIconSize,
   128→                                                        color: 'white',
   129→                                                        style: { transform: `translate(-${travelIconSize / 2}px, -${travelIconSize / 2}px)` },
   130→                                                    })}
   131→                                            </g>
   132→                                        );
   133→                                    })()}
   134→                                </>
   135→                            )}
   136→                        </Geographies>
   137→
   138→                        {/* Origin Marker */}
   139→                        <Marker coordinates={[startPoint.lng, startPoint.lat]}>
   140→                            <g>
   141→                                {/* Draw Circle */}
   142→                                <circle
   143→                                    r={originIconSize * 0.8}
   144→                                    fill={originColor}
   145→                                    
   146→                                />
   147→                                {/* Draw Icon */}
   148→                                {availableIcons[originIcon] &&
   149→                                    React.cloneElement(availableIcons[originIcon], {
   150→                                        size: originIconSize,
   151→                                        color: 'white',
   152→                                        style: { transform: `translate(-${originIconSize / 2}px, -${originIconSize / 2}px)` },
   153→                                    })}
   154→                                {/* Draw Label */}
   155→                                <text
   156→                                    x={getLabelXOffset(labelPosition, originIconSize)}
   157→                                    y={getLabelYOffset(labelPosition, originIconSize, labelSize)}
   158→                                    textAnchor={labelPosition === 'right' ? 'start' : labelPosition === 'left' ? 'end' : 'middle'}
   159→                                    alignmentBaseline={labelPosition === 'top' || labelPosition === 'bottom' ? 'central' : 'middle'}
   160→                                    fontSize={labelSize}
   161→                                    fill="black"
   162→                                >
   163→                                    {originLabel}
   164→                                </text>
